const raw = $input.first().json;
const b = raw.body ?? raw;
const r = b.respostas ?? {};

const sat   = (r.satisfacao_geral ?? '').toLowerCase();
const roi   = (r.percepcao_roi ?? '').toLowerCase();
const saude = (r.saude_financeira ?? '').toLowerCase();
const cont  = (r.continuidade ?? '').toLowerCase();
const unid  = (r.confianca_nova_unidade ?? '').toLowerCase();

// Semáforo do ciclo 2: lê satisfação + ROI + saúde financeira + continuidade
let semaforo = '🟢 OK — sponsor satisfeito e confiante';
let acao = 'Siga com o ciclo e a cobrança com tranquilidade. Reforce o ganho de receita real no próximo contato.';

const vermelho = sat.includes('abaixo')
  || roi.includes('abaixo do que eu esperava')
  || saude.includes('inseguro')
  || saude.includes('preocupado')
  || cont.includes('pausar')
  || cont.includes('encerrar');

const amarelo = sat.includes('dentro do esperado')
  || roi.includes('razoável')
  || saude.includes('atento aos custos')
  || cont.includes('dúvidas')
  || unid.includes('preocupado')
  || unid.includes('cauteloso');

if (vermelho) {
  semaforo = '🔴 ATENÇÃO — risco de insatisfação / custo pesando';
  acao = '⚠️ LIGUE para o Rogério ANTES de qualquer cobrança. Leve o quadro receita x custo na mão e trate o ponto de preocupação primeiro.';
} else if (amarelo) {
  semaforo = '🟡 MORNO — confiança parcial';
  acao = 'Ligação rápida de alinhamento. Mostre o panorama Receita Real x Aporte para ancorar o ROI antes de avançar.';
}

const linhas = [
  '📊 *Pesquisa de Satisfação V2 — Rogério (Advisory · ciclo 2)*',
  semaforo,
  '',
  `*Satisfação geral:* ${r.satisfacao_geral ?? 'N/A'}`,
  `*Retorno x investimento (ROI):* ${r.percepcao_roi ?? 'N/A'}`,
  `*Saúde financeira (receita x custo):* ${r.saude_financeira ?? 'N/A'}`,
  `*Confiança na nova unidade:* ${r.confianca_nova_unidade ?? 'N/A'}`,
  `*Maior entrega:* ${r.maior_entrega ?? 'N/A'}`,
  `*Continuidade:* ${r.continuidade ?? 'N/A'}`,
  `*Prioridade próx. mês:* ${r.prioridade_prox_mes ?? 'N/A'}`,
  '',
  `*Mensagem direta:* ${r.mensagem_mayko || '—'}`,
  '',
  `➡️ *Ação sugerida:* ${acao}`,
];

return [{ json: { mensagem: linhas.join('\n'), numero: '5571982170967' } }];
